namespace Rocks;

/// <summary>
/// Defines the different combinations of 
/// property accessors.
/// </summary>
/// <remarks>
/// This type is designed to be used from code generated by Rocks,
/// and is not intended for general use. Please refrain from
/// referencing it for any other purposes, as its implementation may change.
/// </remarks>
public enum PropertyAccessor
{
	/// <summary>
	/// Used for a "get"
	/// </summary>
	Get,
	/// <summary>
	/// Used for a "set"
	/// </summary>
	Set,
	/// <summary>
	/// Used for a "get/set" 
	/// </summary>
	GetAndSet,
	/// <summary>
	/// Used for a "init" 
	/// </summary>
	Init,
	/// <summary>
	/// Used for a "get/init" 
	/// </summary>
	GetAndInit
}